// Global text size scaling - works on sidebar, canvas, and detail panel
let gTxtScale=_prefs.gTxtScale||1.0;
function applyGlobalTxtScale(){
  document.documentElement.style.setProperty('--txt-scale',gTxtScale);
  document.getElementById('gTxtVal').textContent=Math.round(gTxtScale*100)+'%';
}
document.getElementById('gTxtUp').addEventListener('click',()=>{gTxtScale=Math.min(2.5,gTxtScale+0.15);applyGlobalTxtScale();savePrefs({gTxtScale})});
document.getElementById('gTxtDown').addEventListener('click',()=>{gTxtScale=Math.max(0.5,gTxtScale-0.15);applyGlobalTxtScale();savePrefs({gTxtScale})});

// Sidebar collapse toggle
const _isMobile=()=>window.innerWidth<=768;
const _sb=document.querySelector('.sidebar');
const _sbBtn=document.getElementById('sidebarToggle');
// Cache heavy flag — updated after each render via renderMap()
let _svgHeavy=false;
function _markHeavy(){
  _svgHeavy=document.querySelectorAll('svg *').length>2000;
  if(_svgHeavy){_sb.classList.remove('offscreen');_sb.classList.add('no-anim')}
  else{_sb.classList.remove('no-anim')}
}
// After transform transition ends, mark sidebar offscreen (only for light SVGs that use animation)
_sb.addEventListener('transitionend',(e)=>{
  if(e.propertyName!=='transform')return;
  _sb.classList.remove('animating');
  if(_sb.classList.contains('collapsed')&&!_svgHeavy)_sb.classList.add('offscreen');
});
function _collapseSidebar(){
  if(_svgHeavy){
    // Heavy path: no-anim class already disables transitions via CSS
    _sb.classList.add('collapsed');
    _sbBtn.classList.add('at-origin');
    _sbBtn.textContent='\u25B6';
    return;
  }
  _sb.classList.add('animating','collapsed');
  _sbBtn.classList.add('at-origin');
  _sbBtn.textContent='\u25B6';
}
function _expandSidebar(){
  if(_svgHeavy){
    _sb.classList.remove('offscreen','collapsed');
    _sbBtn.classList.remove('at-origin');
    _sbBtn.textContent='\u25C0';
    return;
  }
  // Remove offscreen first so children paint, then animate on next frame
  _sb.classList.remove('offscreen');
  _sb.classList.add('animating');
  requestAnimationFrame(()=>{_sb.classList.remove('collapsed')});
  _sbBtn.classList.remove('at-origin');
  _sbBtn.textContent='\u25C0';
}
_sbBtn.addEventListener('click',()=>{
  const _pt=performance.now();
  const isCollapsing=!_sb.classList.contains('collapsed');
  if(isCollapsing) _collapseSidebar();
  else _expandSidebar();
  // Show/hide mobile backdrop
  const bd=document.getElementById('mobileBackdrop');
  if(bd){bd.style.display=(!_sb.classList.contains('collapsed')&&_isMobile())?'block':'none'}
  if(!_isMobile()) savePrefs({sidebarCollapsed:_sb.classList.contains('collapsed')});
  console.log('[PERF] sidebar '+(isCollapsing?'collapse':'expand')+': '+(performance.now()-_pt).toFixed(1)+'ms (heavy='+_svgHeavy+')');
});
// Mobile backdrop: tap to close sidebar
(function(){
  const bd=document.createElement('div');
  bd.id='mobileBackdrop';
  bd.style.cssText='display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:99';
  document.body.appendChild(bd);
  bd.addEventListener('click',()=>{
    _collapseSidebar();
    bd.style.display='none';
  });
})();
// Restore sidebar state (collapse on mobile by default)
if(_prefs.sidebarCollapsed||_isMobile()){
  _sb.classList.add('collapsed');
  _sbBtn.classList.add('at-origin');
  _sbBtn.textContent='\u25B6';
}
// Apply saved text scale on load
if(_prefs.gTxtScale) applyGlobalTxtScale();

